head.script:
//==================================================================================================================
// id       : se_105_01_01b
// 이름     : 
// 경로     : 
// 사용계정 : 
// 파라미터 :
//            IN  : 
//            OUT : 
//
// 비고     : 
//           
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     : 
//==================================================================================================================


// 세션 사용자
var mem = $c.data.getMemInfo();
scwin.userId = mem && mem.userId ? mem.userId : "";

// 서버일자
scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");

// JSP 전역 변수/상수 매핑
scwin.MSG_LO_WRN_007 = "Customer와 Dept가 일치하지 않습니다. \n거래처별 매출귀속 정의 화면에서 정보를 확인하세요.";
scwin.MSG_LO_WRN_008 = "이미 전표가 발행  되어 변경 불가능 합니다.";
scwin.MSG_LO_WRN_009 = "Department 가 변경 되었습니다.";

scwin.statusFlag = "";   //수정/등록 Flag(C:Regist, U:Update,I:Init)
scwin.processFlag = "";
scwin.invoiceCheck = "0";
scwin.mhnoFlag = "0"; // 1일때 mhno onloadComplete후 조회.

scwin.v_linkcheck = null;
scwin.v_kcomcd = null; // hd_kcomcd
scwin.v_blno = null;
scwin.v_mhno = null;
scwin.v_bkno = null;
scwin.v_carrierBkno = null;


// 추가 
scwin.v_elno = null;

// 히든
scwin.hd_kcomcd = "DBEX";
scwin.hd_hhio = "O";
scwin.ed_carrierBkNo = "";



// onpageload
scwin.onpageload = function() {
    // 파라미터 세팅
    scwin.v_linkcheck = $c.data.getParameter("linkcheck") || "0";
    scwin.v_kcomcd    = $c.data.getParameter("kcomcd") || "";
    scwin.v_blno      = $c.data.getParameter("blno") || "";
    scwin.v_mhno      = $c.data.getParameter("mhno") || "";
    scwin.v_bkno      = $c.data.getParameter("bkno") || "";
    scwin.v_carrierBkno = $c.data.getParameter("carrierBkno") || "";

    const codeOptions = [
        { grpCd: "IL005", compID: "lc_hhincoterm" }     //열위치
      // , { grpCd: "FI006", compID: "gr_region:acctSummaryCd" }  //적요위치
    ];
    $c.data.setCommonCode(codeOptions);
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = async function () {
    scwin.f_initSetTab(); //tab세팅
    scwin.f_DefaultValue();
    scwin.f_Check();
    await scwin.f_ContainerTypeLoading(); // Container Type 정보
    await scwin.f_getParametrSetting(scwin.v_linkcheck); // link처리
    scwin.f_header();
};

//--------------------------------------------------------------------------
// header dataset 초기화
//--------------------------------------------------------------------------
scwin.f_header = function() {
    // ds_condition_path
    if (ds_condition_path.getRowCount() == 0) {
        ds_condition_path.insertRow(0);
    }
    // ds_result_path 컬럼은 dataList 정의로 대체
};

//---------------------------------------------------------
// Parameter Setting
// 다른 화면에서 들어올때 각 화면별 조건을 받아서 조회한다.
//---------------------------------------------------------
scwin.f_getParametrSetting = async function(gubun) {
    switch (gubun) {

        case "0":
            break;

        case "1": // Booking Search Grid
        case "2": // House Search
            scwin.mhnoFlag = "1";
            if ($c.util.isEmpty(scwin.v_blno)) {
                cnd_ed_hhblno.setValue("");
                cnd_ed_hhblno.focus();
                return false;
            }
            scwin.hd_kcomcd = scwin.v_kcomcd;
            cnd_ed_hhblno.setValue(scwin.v_blno);

            if (ds_hmhno.getRowCount() == 0) {
                ds_hmhno.insertRow(0);
            }
            ds_hmhno.setCellData(0, "code", scwin.v_mhno);
            ds_hmhno.setCellData(0, "name", scwin.v_mhno);

            cnd_lc_mhno.focus();
            break;

        case "4": // Booking 화면에서 create
            await scwin.f_Create();
            ed_hhbkgno.setValue(scwin.v_bkno);
            cnd_ed_hhblno.focus();

            tbc_main.setSelectedTabIndex(0);
            ed_hhbkgno.focus();
            ed_hhetd.focus();
            lc_hhbkgseq.focus();

            // 2020.03.02 ITEM 자동 세팅
            if (txt_hhmitem1.getValue() == "") {     //부킹정보에 아이템 코드없이 아이템 명으로 등록 된 경우가 있으므로 코드값이 아닌 명으로 체크
                ed_hhitem.setValue("30000000");
                // scwin.f_OpenCommonPopUp("Item", "T", "F", "F");
                await scwin.f_OpenCommonPopUpAsync("Item", "T", "F", "F");
            }

            txt_blpic.setValue("");
            //기본으로 등록자 ID 기입 처리
            if (ed_blpic.getValue() == "") {
                ed_blpic.setValue(scwin.userId.replace(/[^0-9]/g, ""));
                // scwin.f_PopUp("B/L PIC", "T");
                await scwin.f_PopUpAsync("B/L PIC", "T");
            }

            await scwin.ed_hhbkgno_onblur();
            lc_hhprenm.setSelectedIndex(0);

            break;
    }
};

// scwin.f_getParametrSetting("4")일 경우 팝업 비동기로 오픈되게함
scwin.f_OpenCommonPopUpAsync = function(gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    return new Promise((resolve) => {
        if (gubun1 === "Item") {
            udc_hhitem.setSelectId("retrieveCommGoodsInfo");
            udc_hhitem.ilCommonPopUp(function (ret) {
                $c.gus.cfSetReturnValue(ret, ed_hhitem, txt_hhmitem1);
                resolve(ret);
            }
            ,ed_hhitem.getValue().trim()
            ,txt_hhmitem1.getValue()
            ,pWinCloseTF
            ,'2'
            ,"Code, Name"
            ,'80,230'
            ,"3,4,5,6,7,8,9,10"
            ,null ,null ,null ,null ,null ,null
            ,pAllSearchTF
            ,"Item,Code,Name"
            ,pNoDataCloseTF
            );
        }
    });
};

// scwin.f_getParametrSetting("4")일 경우 팝업 비동기로 오픈되게함
scwin.f_PopUpAsync = function(disGubun, chgGubun) {
    return new Promise((resolve) => {
        switch (disGubun){

            case "B/L PIC" :
                udc_blpic.setSelectId("retrieveEmpInfo"); 
                udc_blpic.ilCommonPopUp(function (ret) {
                    $c.gus.cfSetReturnValue(ret, ed_blpic, txt_blpic);
                    resolve(ret); 
                },		 
                ed_blpic.getValue().trim(),
                txt_blpic.getValue(),
                "T",
                '4',
                "B/L PIC",
                '100,350',
                null,
                null,
                '500',
                '500',
                null,
                null,
                null,
                "F",
                null);
                break;

            default :
                resolve(null); 
                break;
        }
    });
};


//---------------------------------------------------------
// Object Check (statusFlag 에 따른 초기값)
//---------------------------------------------------------
scwin.f_Check = function() {
    if (scwin.statusFlag == "I" || scwin.statusFlag == "C") {
        cnd_lc_autono.setSelectedIndex(1);
        cnd_lc_mhno.setSelectedIndex(0);
        lc_hhbltype.setSelectedIndex(0);
        lc_hhpcgb.setSelectedIndex(0);
        lc_hhisunm.setSelectedIndex(1);
        lc_hhstype.setSelectedIndex(0);
        lc_hhcoload.setSelectedIndex(0);

        ed_hhcnt1type.setValue("22GP");
        ed_hhcnt2type.setValue("42GP");
        ed_hhcnt3type.setValue("45GP");
        ed_hhobl.setValue("3");

        chb_hhtriange.setValue("0");
        chb_hhnomi.setValue("0");
        chb_hhp1.setValue("1");
        chb_hhp2.setValue("0");
        chb_hhp3.setValue("0");
        chb_hhp4.setValue("1");
        chb_hhp5.setValue("0");
        chb_hhp6.setValue("1");

        rd_hhdanggb.setValue("N");
        rd_hhmnfgb.setValue("E");

        if (scwin.statusFlag == "C") {
            //추가
            ed_hhcnt1.setValue("0");
            ed_hhcnt2.setValue("0");
            ed_hhcnt3.setValue("0");
            ed_hhcnt4.setValue("0");
        }
    }
};

//-------------------------------------------------------------------------
// 초기화
// B/L전화면은 조회조건은 항상 HEADER를 ADDROW상태로 ON LOAD되어있음.
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function() {
    // ds_retrieve, ds_houseblList 등은 dataList 정의로 컬럼이 이미 있음
    // JSP f_setDSHeader 에서 ADDROW 하던 부분만 반영
    if (ds_retrieveNo.getRowCount() == 0) ds_retrieveNo.insertRow(0);
    if (ds_bookingNo.getRowCount() == 0) ds_bookingNo.insertRow(0);
    if (ds_bookingContainer.getRowCount() == 0) ds_bookingContainer.insertRow(0);
    if (ds_hmhno.getRowCount() == 0) ds_hmhno.insertRow(0);
    if (ds_clntNo.getRowCount() == 0) ds_clntNo.insertRow(0);

    scwin.f_Set("INIT");

    cnd_ed_hhblno.focus();
};


//---------------------------------------------------------
// Tab 초기화
//---------------------------------------------------------
scwin.f_initSetTab = function() {
    // 기존 cfEnableObjects([tr_tab_center0,...]) → 탭컨트롤은 이미 활성
 //   $c.gus.cfEnableObjects([tr_tab_center0, tr_tab_center1,tr_tab_center2]);
    scwin.cfViewTab(0);
};

scwin.cfViewTab = function(idx) {
    tbc_main.setSelectedTabIndex(idx);
};

//---------------------------------------------------------
// Tab Menu 선택
//---------------------------------------------------------
scwin.f_selectTabMenu = function(idx) {
    scwin.cfViewTab(idx);
};

//---------------------------------------------------------
// 상태별 화면 제어
//---------------------------------------------------------
scwin.f_Set = function(gubun) {
    switch (gubun) {

        case "INIT":
            $c.gus.cfDisableKeyData(); /// Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            $c.gus.cfDisableBtnOnly([btn_Copy,btn_Cancel, btn_FileDownload, btn_Save, btn_Delete, btn_Update
    		                        ,btn_1,btn_2,btn_3,btn_4,btn_5,btn_6,btn_7,btn_8
    		                        ,btn_CntrReceive,btn_AddRow1,btn_AddCntr,btn_DelRow1,btn_CancelRow1,btn_AddRow2,btn_DelRow2,btn_CancelRow2, pu_departmentChange
    		                        ,txt_hhmitem1]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_9]);
            scwin.f_DisablePopUpObj();
            ed_eltotwgt.setReadOnly(true);
            // 검색영역 enable
            $c.gus.cfEnableObjects([tbl_Search]);   // 조회조건.

            scwin.statusFlag = "I";
            break;

        case "RETRIEVE":
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Save,  btn_Cancel
									,btn_CntrReceive,btn_AddRow1,btn_AddCntr,btn_DelRow1,btn_CancelRow1,btn_AddRow2,btn_DelRow2,btn_CancelRow2
									,txt_hhmitem1]);

            $c.gus.cfEnableBtnOnly([btn_Copy,btn_Create, btn_Delete, btn_FileDownload
    		                        ,btn_4,btn_5,btn_6,btn_7,btn_8,btn_9, pu_departmentChange]);

            // 그리드 readOnly : 수정 불가 
            scwin.f_setGridColumnsReadOnly(gr_ocContList, true);
            scwin.f_setGridColumnsReadOnly(gr_ocElList, true);
              ed_eltotwgt.setReadOnly(false);
            if (scwin.statusFlag == "C") {
                $c.gus.cfDisableBtnOnly([btn_Update]);
            } else {
                $c.gus.cfEnableBtnOnly([btn_Update]);
            }
            // 검색영역 enable
            $c.gus.cfEnableObjects([tbl_Search]); // 조회조건.
            scwin.statusFlag = "";  // flag null
            break;

        case "CREATE":
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();

            $c.gus.cfDisableBtnOnly([btn_Copy,btn_Create, btn_Update, btn_Delete,btn_4,btn_5,btn_6,btn_7,btn_8, pu_departmentChange
            	,txt_hhmitem1]);

            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, btn_FileDownload
            					,btn_1,btn_2,btn_3,btn_9
								,btn_CntrReceive,btn_AddRow1,btn_AddCntr,btn_DelRow1,btn_CancelRow1,btn_AddRow2,btn_DelRow2,btn_CancelRow2]);

            // 그리드 readOnly : 수정 가능  
            ed_eltotwgt.setReadOnly(false);
            scwin.f_setGridColumnsReadOnly(gr_ocContList, false);
            scwin.f_setGridColumnsReadOnly(gr_ocElList, false);
            $c.gus.cfDisableObjects([tbl_Search]); // 조회조건.
            $c.gus.cfEnableObjects([cnd_ed_hhblno,cnd_lc_autono]); // 조회조건.
            scwin.statusFlag = "C";
            break;

        case "UPDATE":
            $c.gus.cfDisableBtnOnly([btn_Copy,btn_Update, btn_Create, btn_Delete,btn_4,btn_5,btn_6,btn_7,btn_8, pu_departmentChange]);

            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, btn_FileDownload
            					,btn_1,btn_2,btn_3,btn_9
            					,btn_CntrReceive,btn_AddRow1,btn_AddCntr,btn_DelRow1,btn_CancelRow1,btn_AddRow2,btn_DelRow2,btn_CancelRow2
            					,txt_hhmitem1,txt_hhmitem2]);

            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();
            ed_eltotwgt.setReadOnly(false);

            // 그리드 readOnly : 수정 가능  
            scwin.f_setGridColumnsReadOnly(gr_ocContList, false);
            scwin.f_setGridColumnsReadOnly(gr_ocElList, false);
            $c.gus.cfDisableObjects([tbl_Search]);
            scwin.statusFlag = "U";
            break;

        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Delete, btn_Cancel, btn_FileDownload]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create]);
            ed_eltotwgt.setReadOnly(false);
            scwin.f_Set("RETRIEVE");
            break;
    }
};


//-------------------------------------------------------------------------
// PopUp 이미지 enable/disable
//-------------------------------------------------------------------------
scwin.f_EnablePopUpObj = function() {
    // img_Date 1~5
    $c.gus.cfEnableObjects([ed_hhetd,ed_hhondt,ed_hheta,ed_hhisudt,ed_creadyDt]);

    // img_PopUp 1~24
    $c.gus.cfEnableObjects([btn_hhscd, btn_popHhccd, btn_popHhncd, btn_hhvslcd, btn_hhlodcd, btn_hhdisccd, btn_hhunitcd,
                            btn_hhagent, btn_hhagentattn, btn_hhactcust, btn_hhactattn, btn_hhsales, btn_hhliner, btn_hhlinerattn,
                            btn_hhbuyer, btn_hhitem, btn_hhrcvcd, btn_hhdlvcd, btn_hhfdcd, btn_popHhcnt1type, btn_popHhcnt2type, btn_popHhcnt3type, btn_popHhcnt4type]);

    // btn_mwarecd, btn_blpic = img_PopUp25 id 중복(asis)
    $c.gus.cfEnableObjects([btn_mwarecd, btn_blpic]);
};

scwin.f_DisablePopUpObj = function() {
    // img_Date1,img_Date2,img_Date3,img_Date4,img_Date5
    $c.gus.cfDisableObjects([ed_hhetd,ed_hhondt,ed_hheta,ed_hhisudt,ed_creadyDt]);

    // img_PopUp 1~24
    $c.gus.cfDisableObjects([btn_hhscd, btn_popHhccd, btn_popHhncd, btn_hhvslcd, btn_hhlodcd, btn_hhdisccd, btn_hhunitcd,
                             btn_hhagent, btn_hhagentattn, btn_hhactcust, btn_hhactattn, btn_hhsales, btn_hhliner, btn_hhlinerattn,
                             btn_hhbuyer, btn_hhitem, btn_hhrcvcd, btn_hhdlvcd, btn_hhfdcd, btn_popHhcnt1type, btn_popHhcnt2type, btn_popHhcnt3type, btn_popHhcnt4type]);

    // btn_mwarecd, btn_blpic = img_PopUp25 id 중복(asis)
    $c.gus.cfDisableObjects([btn_mwarecd, btn_blpic]);
};



// (tobe 추가) 그리드 readonly로 editable 설정하기 
scwin.f_setGridColumnsReadOnly = function (gridObj, readOnly) {
    if (!gridObj) return;

    var cols = gridObj.getColumnIdListMultiRow && gridObj.getColumnIdListMultiRow();
    cols = (cols && cols.length > 0) ? cols[0] : null;
    if (!cols) return;

    for (var i = 0; i < cols.length; i++) {
        if (gridObj.setColumnReadOnly) {
            gridObj.setColumnReadOnly(cols[i], !!readOnly);
        }
    }
};



//---------------------------------------------------------
// 조회
//---------------------------------------------------------
scwin.f_Retrieve = async function() {

    if (cnd_ed_hhblno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House No"]);  // @은(는) 필수 입력 항목입니다.
    };


    cnd_lc_mhno.focus(); // B/L No 빠져나올때 event처리 .

    ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
    ds_retrieve.set("mhno", cnd_lc_mhno.getValue());
    ds_retrieve.set("hhio", scwin.getHiddenHhio());

    ds_bkseq.removeAll();
    ds_bkseq.insertRow(0);
    ds_bkseq.setRowPosition(0);

    $c.sbm.execute(sbm_retrieve);
};


//---------------------------------------------------------
// 조회 조건 지우기 (btn_clear)
//---------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects([cnd_ed_hhblno, cnd_ed_hhmblno]);
	cnd_lc_autono.setSelectedIndex(1); //입력 COMBO
    ds_hmhno.removeAll(); // DATASET COMBO
};


//-------------------------------------------------------------------------
// Create
//-------------------------------------------------------------------------
scwin.f_Create = async function() {
    scwin.f_FieldClear();

    var r = ds_hmhno.insertRow(ds_hmhno.getRowCount());
    ds_hmhno.setRowPosition(r);

    ds_houseblList.removeAll();
    ds_houseblList.insertRow(0);
    ds_houseblList.setRowPosition(0);

    ds_ocContList.removeAll();
    ds_ocElList.removeAll();
    ds_slipTax.removeAll();
    ds_ocProfitList.removeAll();

    ed_totcnt.setValue(" 총 0건");
    ed_eltotcnt.setValue(" 총 0건");

    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
	$c.gus.cfEnableObj(cnd_lc_mhno, true);

    scwin.f_Set("CREATE");
    scwin.f_Check();

    cnd_ed_hhblno.setValue("DBEX");
    cnd_ed_hhblno.focus();

    ed_hhitem.setValue("30000000");
    scwin.f_OpenCommonPopUp("Item", "T", "F", "F");

    txt_blpic.setValue("");
    ed_blpic.setValue(scwin.userId.replace(/[^0-9]/g, ""));
    // scwin.f_PopUp("B/L PIC", "T");
    await scwin.f_PopUpAsync("B/L PIC", "T");
};



//-------------------------------------------------------------------------
// Update
//-------------------------------------------------------------------------
scwin.f_Update = async function() {
    if (ed_hhetd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
        return;
    }
    scwin.f_Set("UPDATE");
    await scwin.f_invoiceCheck();

    $c.gus.cfDisableObjects([ed_hhbuyer, txt_hhbuyernm, btn_hhbuyer ]);
};


//---------------------------------------------------------
// 저장
// 1. HOUSE B/L NO 를 DBEX로 시작하는 자동 NUMBERING 
// 2. HOUSE HEADER를 생성한다.
// 3. UPDATE 모드로 CONTAINER 및 적하목록을 등록한다.
// MARK, DISCRIPTION은 CLOB으로 이루어져 있다.
//---------------------------------------------------------
scwin.f_Save = async function() {
    if (ds_houseblList.getModifiedIndex().length == 0 && ds_ocContList.getModifiedIndex().length == 0 && ds_ocElList.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["House B/L"]); // @은(는) 변경된 사항이 없습니다
        return;
    }

    if (!await scwin.f_validate()) return;

    var ok = await $c.win.confirm(E_MSG_CM_CRM_001); // "저장하시겠습니까?"
    if (!ok) return;

    if (scwin.statusFlag == "C") {
        // DBEX
        if (cnd_ed_hhblno.getValue().length == 4 && cnd_ed_hhblno.getValue() == "DBEX") {
            // House B/L NO 를 생성및 가져온다.(creadyDt로 번호 생성)
            ds_retrieve.set("hhetd", ds_houseblList.getCellData(0, "creadyDt") || "");
            let e = await $c.sbm.execute(sbm_retrievehouseBlNo);

            // if (ds_retrieveNo.getRowCount() > 0) {
            if (e.responseJSON.OUT_DS1.length > 0) {
                var newNo = ds_retrieveNo.getCellData(0, "hhblno");
                cnd_ed_hhblno.setValue(newNo);
            }
        }

        ds_houseblList.setCellData(0, "kcomcd", scwin.hd_kcomcd);
        ds_houseblList.setCellData(0, "hhblno", cnd_ed_hhblno.getValue() || "");
        ds_houseblList.setCellData(0, "hhbkgseq", lc_hhbkgseq.getValue() || "");
        ds_houseblList.setCellData(0, "mhno", cnd_lc_mhno.getValue() || "");
        ds_houseblList.setCellData(0, "hhisunm", lc_hhisunm.getValue() || "");
        ds_houseblList.setCellData(0, "hhpaynm", lc_hhpaynm.getValue() || "");
        ds_houseblList.setCellData(0, "hhpcgb", lc_hhpcgb.getValue() || "");
        ds_houseblList.setCellData(0, "hhio", scwin.getHiddenHhio());
        ds_houseblList.setCellData(0, "inpid", scwin.userId);

        // Container
        for (var i = 0; i < ds_ocContList.getRowCount(); i++) {
            ds_ocContList.setCellData(i, "kcomcd", scwin.hd_kcomcd);
            ds_ocContList.setCellData(i, "mchblno", cnd_ed_hhblno.getValue() || "");
            ds_ocContList.setCellData(i, "mhno", cnd_lc_mhno.getValue() || "");
            ds_ocContList.setCellData(i, "inpid", scwin.userId);
        }

        // EL
        for (var j = 0; j < ds_ocElList.getRowCount(); j++) {
            ds_ocElList.setCellData(j, "kcomcd", scwin.hd_kcomcd);
            ds_ocElList.setCellData(j, "hhblno", cnd_ed_hhblno.getValue() || "");
            ds_ocElList.setCellData(j, "mhno", cnd_lc_mhno.getValue() || "");
            ds_ocElList.setCellData(j, "inpid", scwin.userId);
            ds_ocElList.modifyRowStatus(j, "C");    // ds_ocElList.UserStatus(i)=1;  // insert 로 변경.
        }
    }

    // Booking Seq 필수
    if (lc_hhbkgseq.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Booking Seq"]); // @이(가) 존재하지 않습니다.
        return;
    }

    // Shipper/Consignee/Notify 길이 체크
    if (txt_hhs1.getValue().length > 100) {
        await $c.win.alert("Shipper명을 100자리를 초과하여 입력하면 EDI전송이 안됩니다. 100자리 이하로 맞춰주세요 \n 현재 자리수 : " + txt_hhs1.getValue().length);
        txt_hhs1.focus();
        return;
    }
    if (txt_hhs2.getValue().length > 100) {
        await $c.win.alert("Consignee명을 100자리를 초과하여 입력하면 EDI전송이 안됩니다. 100자리 이하로 맞춰주세요 \n 현재 자리수 : " + txt_hhs2.getValue().length);
        txt_hhs2.focus();
        return;
    }
    if (txt_hhs3.getValue().length > 100) {
        await $c.win.alert("Notify명을 100자리를 초과하여 입력하면 EDI전송이 안됩니다. 100자리 이하로 맞춰주세요 \n 현재 자리수 : " + txt_hhs3.getValue().length);
        txt_hhs3.focus();
        return;
    }

    // MgntClnt 체크
    if (ds_clntNo.getRowCount() == 0) {
        ds_clntNo.insertRow(0);
        ds_clntNo.setRowPosition(0);
    }
    ds_clntNo.setCellData(0, "hhactcust", ed_hhactcust.getValue());

    let e = await $c.sbm.execute(sbm_retrieveMgntClnt);

    if (e.responseJSON.OUT_DS1.length > 0) {
        if (ds_mgntYn.getCellData(0, "mgntYn") == "Y") {
            await $c.win.alert("해당 Customer는 관리거래처이므로 B/L 발급을 불허합니다.");
        }
    }

    // B/L PIC값이 없을때 등록자 아이디로 입력(PIC값이 null되는걸 방지)
    if (ed_blpic.getValue() == "") {
        txt_blpic.setValue("");
        ds_houseblList.setCellData(0, "pic", scwin.userId);
    }

    $c.sbm.execute(sbm_save);
};



