scwin.f_Cancel = function() {
    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
	$c.gus.cfEnableObj(cnd_lc_mhno, true);

    cnd_ed_hhblno.focus();

    if (scwin.statusFlag == "C") {
        scwin.f_Set("INIT");
    } else {
        scwin.f_Set("RETRIEVE");
        ds_houseblList.undoAll();
        scwin.f_cancelRow(1);
		scwin.f_cancelRow(2);

        // 빈문자열 넘어와서 replace처리
        scwin.f_removeNullString(txa_descnm);
    }
};


//-------------------------------------------------------------------------
// Copy
// 기존의 조회된 HOUSE HEADER정보만을 COPY한다. 저장시 HOUSE NO만 바뀌는 결과.
//-------------------------------------------------------------------------
scwin.f_Copy = function() {
    scwin.f_FieldClear();

 //   ds_hmhno.removeAll();
    ds_hmhno.insertRow(0);
    ds_hmhno.setRowPosition(0);

    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
	$c.gus.cfEnableObj(cnd_lc_mhno, true);

    scwin.f_Set("CREATE");

    cnd_ed_hhblno.setValue("DBEX");

    cnd_lc_autono.setSelectedIndex(1);

    cnd_lc_mhno.setSelectedIndex(0);
    cnd_lc_mhno.setValue("NONE");

    if (ds_houseblList.getRowCount() != 0) {
        // UserStatus=1 → 신규로 간주
        ds_houseblList.modifyRowStatus(0, "C");  // insert 로 변경.
    }

    ds_ocContList.removeAll();
    ds_ocElList.removeAll();

    cnd_ed_hhblno.focus();

    if (ed_hhccd.getValue() != "") {
        ed_hhactcust.setValue(ed_hhccd.getValue());
        txt_hhactcustnm.setValue(txt_hhc1.getValue());
    } else if (ed_hhncd.getValue() != "") {
        ed_hhactcust.setValue(ed_hhncd.getValue());
        txt_hhactcustnm.setValue(txt_hhn1.getValue());
    }

    txt_blpic.setValue("");
    //기본으로 등록자 ID 기입 처리
    if ($c.util.isEmpty(ed_blpic.getValue())) {
        ed_blpic.setValue(scwin.userId.replace(/[^0-9]/g, ""));
        scwin.f_PopUp("B/L PIC", "T");
    }
};


//---------------------------------------------------------
// 삭제
// 삭제는 저장의 역순으로 지워진다.
//---------------------------------------------------------
scwin.f_Delete = async function() {
    await scwin.f_invoiceCheck();

    if (scwin.invoiceCheck == "1") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No","delete"]);  // @은(는) @할 수 없습니다.
        return;
    }

    // Mhno 존재
    if (cnd_lc_mhno.getValue() !== "NONE") {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_011, ["Document No"]);    // 이미 존재하는 @입니다.
        return;
    }

    if (await $c.win.confirm(E_MSG_CM_CRM_004)) { //삭제하시겠습니까?
        let e = await $c.sbm.execute(sbm_delete)
        if (e.responseJSON.resultDataSet[0].Code < 0) return;

        // onsubmitdone
        await $c.gus.cfAlertMsg(E_MSG_CM_INF_004);

        cnd_ed_hhblno.setValue("");

        ds_houseblList.removeAll();
        ds_ocContList.removeAll();
        ds_ocElList.removeAll();
        ds_slipTax.removeAll();
        ds_ocProfitList.removeAll();

        $c.gus.cfEnableObj(cnd_ed_hhblno, true);
        $c.gus.cfEnableObj(cnd_lc_mhno, true);

        cnd_ed_hhblno.focus();
        scwin.f_Set("INIT");
    }
};


//---------------------------------------------------------
// isEmpty
//---------------------------------------------------------
scwin.isEmpty = function(value) {
    if (value == null || ("" + value).length == 0) {
        return 0;
    }
    return parseFloat(value);
};


//---------------------------------------------------------
// Auto Container Info 행추가
//---------------------------------------------------------
scwin.f_addCntr = function() {
    var hhcnt1 = scwin.isEmpty(ed_hhcnt1.getValue());
    var hhcnt2 = scwin.isEmpty(ed_hhcnt2.getValue());
    var hhcnt3 = scwin.isEmpty(ed_hhcnt3.getValue());
    var hhcnt4 = scwin.isEmpty(ed_hhcnt4.getValue());
    var hhcnt = parseInt(hhcnt1 + hhcnt2 + hhcnt3 + hhcnt4, 10);

    var hhcnt1type = ed_hhcnt1type.getValue();
    var hhcnt2type = ed_hhcnt2type.getValue();
    var hhcnt3type = ed_hhcnt3type.getValue();
    var hhcnt4type = ed_hhcnt4type.getValue();

    var hhpkg = parseInt(scwin.isEmpty(ed_hhpkg.getValue()) / hhcnt, 10);
    var hhgwgt = (scwin.isEmpty(ed_hhgwgt.getValue()) / hhcnt).toFixed(3);
    var hhmsr = (scwin.isEmpty(ed_hhmsr.getValue()) / hhcnt).toFixed(3);

    var hhpkgSum = 0;
    var hhgwgtSum = 0;
    var hhmsrSum = 0;
    var cntSum = 1;

    for ( var i = 0; i < hhcnt1; i++) {
        ds_ocContList.insertRow();
        ds_ocContList.setRowPosition(ds_ocContList.getRowCount() - 1);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcpkg", hhpkg);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcwgt", hhgwgt);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcmsr", hhmsr);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mchblno", cnd_ed_hhblno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mhno", cnd_lc_mhno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "inpid", scwin.userId);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mctype", hhcnt1type);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcpkgcd", ed_hhunitcd.getValue());

        if (cntSum != hhcnt) {
            hhpkgSum = scwin.isEmpty(hhpkgSum) + scwin.isEmpty(hhpkg);
            hhgwgtSum = scwin.isEmpty(hhgwgtSum) + scwin.isEmpty(hhgwgt);
            hhmsrSum = scwin.isEmpty(hhmsrSum) + scwin.isEmpty(hhmsr);
        }
        cntSum++;
    }

    for ( var i = 0; i < hhcnt2; i++) {
        ds_ocContList.insertRow();
        ds_ocContList.setRowPosition(ds_ocContList.getRowCount() - 1);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mchblno", cnd_ed_hhblno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mhno", cnd_lc_mhno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "inpid", scwin.userId);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mctype", hhcnt2type);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcpkgcd", ed_hhunitcd.getValue());
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcpkg", hhpkg);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcwgt", hhgwgt);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcmsr", hhmsr);

        if (cntSum != hhcnt) {
            hhpkgSum = scwin.isEmpty(hhpkgSum) + scwin.isEmpty(hhpkg);
            hhgwgtSum = scwin.isEmpty(hhgwgtSum) + scwin.isEmpty(hhgwgt);
            hhmsrSum = scwin.isEmpty(hhmsrSum) + scwin.isEmpty(hhmsr);
        }
        cntSum++;
    }

    for ( var i = 0; i < hhcnt3; i++) {
        ds_ocContList.insertRow();
        ds_ocContList.setRowPosition(ds_ocContList.getRowCount() - 1);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mchblno", cnd_ed_hhblno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mhno", cnd_lc_mhno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "inpid", scwin.userId);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mctype", hhcnt3type);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcpkgcd", ed_hhunitcd.getValue());
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcpkg", hhpkg);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcwgt", hhgwgt);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcmsr", hhmsr);

        if (cntSum != hhcnt) {
            hhpkgSum = scwin.isEmpty(hhpkgSum) + scwin.isEmpty(hhpkg);
            hhgwgtSum = scwin.isEmpty(hhgwgtSum) + scwin.isEmpty(hhgwgt);
            hhmsrSum = scwin.isEmpty(hhmsrSum) + scwin.isEmpty(hhmsr);
        }
        cntSum++;
    }

    for ( var i = 0; i < hhcnt4; i++) {
        ds_ocContList.insertRow();
        ds_ocContList.setRowPosition(ds_ocContList.getRowCount() - 1);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mchblno", cnd_ed_hhblno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mhno", cnd_lc_mhno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "inpid", scwin.userId);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mctype", hhcnt4type);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcpkgcd", ed_hhunitcd.getValue());
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcpkg", hhpkg);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcwgt", hhgwgt);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition(), "mcmsr", hhmsr);

        if (cntSum != hhcnt) {
            hhpkgSum = scwin.isEmpty(hhpkgSum) + scwin.isEmpty(hhpkg);
            hhgwgtSum = scwin.isEmpty(hhgwgtSum) + scwin.isEmpty(hhgwgt);
            hhmsrSum = scwin.isEmpty(hhmsrSum) + scwin.isEmpty(hhmsr);
        }
        cntSum++;
    }

    ds_ocContList.setCellData(ds_ocContList.getTotalRow() - 1, "mcpkg", scwin.isEmpty(ed_hhpkg.getValue()) - hhpkgSum);
    ds_ocContList.setCellData(ds_ocContList.getTotalRow() - 1, "mcwgt", scwin.isEmpty(ed_hhgwgt.getValue()) - hhgwgtSum);
    ds_ocContList.setCellData(ds_ocContList.getTotalRow() - 1, "mcmsr", scwin.isEmpty(ed_hhmsr.getValue()) - hhmsrSum);
};

