//---------------------------------------------------------
// Cargo Control
// 숫자를 영문으로 변환하거나 다른 포멧으로 변경한다.
//---------------------------------------------------------
scwin.f_cargoControl = function() {
    if (scwin.statusFlag == "C" || scwin.statusFlag == "U") {
        if (lc_hhbltype.getValue() == "F") {

            txt_hhsubpkg.setValue("");
            txt_hhunit2.setValue("");
            txt_hhsay.setValue("");

            let result = "";
            let resultSay = "";
            let resultCnt = 0;

            const nameByCode = (code) => {
                const idx = ds_containerType.getMatchedIndex("code", code);
                return idx < 0 ? "" : ds_containerType.getCellData(idx, "name");
            };

            const add = (typeCode, qty, prevQty) => {
                if ($c.util.isEmpty(typeCode) || $c.util.isEmpty(qty) || qty == "0") return 0;

                const nm = nameByCode(typeCode);
                if ($c.util.isEmpty(nm)) return 0;

                const strc = nm + " X " + qty;

                if ($c.util.isEmpty(result)) {
                    result = strc;
                    resultSay = scwin.cf_NumChangeEng(qty) + "(" + strc + ")";
                } else {
                    result = result + " & " + strc;
                    resultSay = resultSay + " & " + scwin.cf_NumChangeEng(qty) + "(" + strc + ")";
                }
                return parseInt(qty, 10) || 0;
            };

            resultCnt += add(ed_hhcnt1type.getValue(), ed_hhcnt1.getValue());
            resultCnt += add(ed_hhcnt2type.getValue(), ed_hhcnt2.getValue());
            resultCnt += add(ed_hhcnt3type.getValue(), ed_hhcnt3.getValue());
            resultCnt += add(ed_hhcnt4type.getValue(), ed_hhcnt4.getValue());

            txt_hhsubpkg.setValue(result);

            // Number of Containers or Packages2
            if (!$c.util.isEmpty(ed_hhpkg.getValue()) && ed_hhpkg.getValue() !== "0") {
                txt_hhunit2.setValue(ed_hhpkg.getValue() + " " + txt_hhunit.getValue());
            }

            // Say
            if (resultCnt == 1) {
                txt_hhsay.setValue(resultSay + " CONTAINER ONLY");
            } else {
                txt_hhsay.setValue(resultSay + " CONTAINERS ONLY");
            }

            // Print option
            chb_hhp1.setValue("1");
            chb_hhp2.setValue("1");
            chb_hhp3.setValue("1");

        } else if (lc_hhbltype.getValue() == "L") {

            txt_hhsubpkg.setValue("");
            txt_hhunit2.setValue("");
            txt_hhsay.setValue("");

            // Number of Containers or Packages
            if (!$c.util.isEmpty(ed_hhpkg.getValue()) && ed_hhpkg.getValue() != "0") {
                txt_hhsubpkg.setValue(ed_hhpkg.getValue() + " " + txt_hhunit.getValue());
            }

            // Say
            if (!$c.util.isEmpty(ed_hhpkg.getValue()) && ed_hhpkg.getValue() != "0") {
                const v = scwin.cf_NumChangeEng(ed_hhpkg.getValue());
                if (ed_hhpkg.getValue() == "1") {
                    txt_hhsay.setValue(v + "(" + ed_hhpkg.getValue() + ") " + txt_hhunit.getValue() + " ONLY");
                } else {
                    txt_hhsay.setValue(v + "(" + ed_hhpkg.getValue() + ") " + txt_hhunit.getValue() + "'S ONLY");
                }
            }

            // Print option
            chb_hhp1.setValue("0");
            chb_hhp2.setValue("1");
            chb_hhp3.setValue("0");
        } else {
            return;
        }
    }
};



//---------------------------------------------------------
// Booking Search Popup
// BOOKING NO에 값을입력하지 않고,TAB을 눌렸을때 POPUP 창을 띄워 BOOKING을 조회하는 화면을 구성.
//---------------------------------------------------------
scwin.f_bookingSearchPopup = async function() {
    let opts = {
        id: "se_103_01_01p",
        popupName: "Booking Search",
        modal: true,
        type: "browserPopup",
        width: 1325,
        height: 780,
        title: "Booking Search"
    };
    let data = { v_hhio: scwin.hd_hhio };
    const ret = await $c.win.openPopup("/ui/il/seaout/sobk/se_103_01_01p.xml", opts, data);

    // 팝업 리턴값 기준(프로젝트 규격에 맞게 key 조정)
    ed_hhbkgno.setValue(ret ?? "");

    scwin.cfViewTab(0);

    if (!$c.util.isEmpty(ed_hhbkgno.getValue())) {
        ed_hhbkgno.focus();
        scwin.f_retrieveCarrierBkNo();
    } else {
        lc_hhbkgseq.focus();
    }
    return false;
};


//---------------------------------------------------------
// Container Type 중복 체크
//---------------------------------------------------------
scwin.f_containerDualCheck = async function() {
    // Container Type 중복 체크
    const types = [
        ed_hhcnt1type.getValue(),
        ed_hhcnt2type.getValue(),
        ed_hhcnt3type.getValue(),
        ed_hhcnt4type.getValue()
    ].filter(v => !$c.util.isEmpty(v));

    const hasDup = new Set(types).size !== types.length;

    if (hasDup) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, ["Container Type"]); // @은(는) 중복될 수 없습니다.
        return false;
    }
    return true;
};


//---------------------------------------------------------
// 수출신고번호 Check
//---------------------------------------------------------
scwin.f_elnoExportCheck = async function(elno) {
    if ($c.util.isEmpty(elno) || !/^\d{15}$/.test(elno)) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_038, ["수출신고번호"]);
        return false;
    }

    const chkCode = elno.charCodeAt(14) - 48; // 0~9
    const weights = [7,3,1,7,3,1,7,3,1,7,3,1,7,3];

    let sum = 0;
    for (let i = 0; i < 14; i++) {
        const d = elno.charCodeAt(i) - 48;
        sum += (d * weights[i]) % 10;
    }

    let result = sum % 10;
    if (result > 0) result = 10 - result;

    if (chkCode !== result) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_038, ["수출신고번호"]);
        return false;
    }
    return true;
};


//-------------------------------------------------------------------------
// 화물관리번호  Check
//-------------------------------------------------------------------------
scwin.f_elnoReshipmentCheck = async function(elno) {
    // 11자리 숫자(0~10), 10번째가 체크자리
    if ($c.util.isEmpty(elno) || !/^\d{11}$/.test(elno)) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_038, ["화물관리번호"]);
        return false;
    }

    const chkCode = elno.charCodeAt(10) - 48; // '0'~'9' -> 0~9
    const weights = [3,7,9,3,7,9,3,7,9,3];

    let sum = 0;
    for (let i = 0; i < 10; i++) {
        const d = elno.charCodeAt(i) - 48;
        sum += (d * weights[i]) % 10;
    }

    const result = sum % 10;

    if (chkCode !== result) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_038, ["화물관리번호"]);
        return false;
    }
    return true;
};


