scwin.f_departmentChange = async function () {
    if (ed_hhbuyer.getValue() != "") {

        var opts = {
                id : ""
                , popupName : ""
                , modal : true
                , type : "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
