            pdeptnm : txt_hhbuyernm.getValue()
        }
        var rtnList = await $c.win.openPopup("/ui/il/common/xml/ilCommonDeptChange.xml", opts, data);
                                                                    // rtnList[0] = "N/A" ;
                                                                    // rtnList[1] = ed_newdept.Text;
                                                                    // rtnList[2] = txt_newdeptnm.value;

        if (rtnList != null) {
            if ( rtnList[0] == "N/A" && rtnList[1] != "" && rtnList[2] != "" ) {
                // 부서 변경  프로시저 호출 시작
                ds_DeptChangeParam.removeAll();
                ds_DeptChangeParam.insertRow(0);

                ds_DeptChangeParam.setCellData(0, "modrNo" , "");
                ds_DeptChangeParam.setCellData(0, "hodrNo" , ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "odrNo"));	// Order No
