scwin.f_Import = function() {
    // ds_tmp.ImportData(ds_ExcelInformation.ExportData(1, ds_ExcelInformation.CountRow, true));
    ds_tmp.setJSON(ds_ExcelInformation.getAllJSON());

    for (var i = 0 ; i < ds_tmp.getTotalRow(); i++) {
            ds_ocContList_upload.insertRow(i);
            ds_ocContList_upload.setCellData(i, "mccntno"		, ds_tmp.getCellData(i, "mccntno" ));
            ds_ocContList_upload.setCellData(i, "mctype"		, ds_tmp.getCellData(i, "mctype" ));
            ds_ocContList_upload.setCellData(i, "mcseal1"		, ds_tmp.getCellData(i, "mcseal1" ));
            ds_ocContList_upload.setCellData(i, "mcseal2"		, ds_tmp.getCellData(i, "mcseal2" ));
            ds_ocContList_upload.setCellData(i, "mcpkg"		    , $c.str.trim(ds_tmp.getCellData(i, "mcpkg" ).replace(",","")));
            ds_ocContList_upload.setCellData(i, "mcpkgcd"		, ds_tmp.getCellData(i, "mcpkgcd" ));
            ds_ocContList_upload.setCellData(i, "mcwgt"		    , $c.str.trim(ds_tmp.getCellData(i, "mcwgt" ).replace(",","")));
            ds_ocContList_upload.setCellData(i, "mcmsr"		    , $c.str.trim(ds_tmp.getCellData(i, "mcmsr" ).replace(",","")));
            ds_ocContList_upload.setCellData(i, "mcpart"		, ds_tmp.getCellData(i, "mcpart" ));
            //공통사항
            ds_ocContList_upload.setCellData(i, "kcomcd", scwin.hd_kcomcd);
            ds_ocContList_upload.setCellData(i, "mchblno", cnd_ed_hhblno.getValue());
            ds_ocContList_upload.setCellData(i, "mhno", cnd_lc_mhno.getValue());
            ds_ocContList_upload.setCellData(i, "inpid", scwin.userId);
    }

    ds_tmp.removeAll();
};


