//---------------------------------------------------------
// submission 이벤트 핸들러
//---------------------------------------------------------
scwin.sbm_retrieve_submitdone = async function() {
    // 기존 tr 후  Booking Seq
    var hhbkgseq = ds_houseblList.getRowCount() > 0 ? ds_houseblList.getCellData(0, "hhbkgseq") : "";
    if (hhbkgseq) {
        ds_bkseq.setCellData(0, "code", hhbkgseq);
    }
    lc_hhbkgseq.setSelectedIndex(0);

    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
    $c.gus.cfEnableObj(cnd_lc_mhno, true);

    txt_blpic.setValue("");
    if (ed_blpic.getValue() != "") {
        scwin.f_PopUp("B/L PIC", "T");
    }

    // tr_retrieve" event="OnSuccess()"
    if (ds_houseblList.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002); 
        scwin.f_Set("INIT");
        scwin.f_Check();

    } else {
        ed_totcnt.setValue(" 총 " + ds_ocContList.getTotalRow() + "건");
        ed_eltotcnt.setValue(" 총 " + ds_ocElList.getTotalRow() + "건");

        ds_houseblList.setRowPosition(0); // 데이터 선택 
        ds_ocContList.setRowPosition(0);
        ds_slipTax.setRowPosition(0);
        ds_ocProfitList.setRowPosition(0);
        /* ds_bkseq.setJSON([{
            code: ds_houseblList.getCellData(0, "hhbkgseq"),
            name: ds_houseblList.getCellData(0, "hhbkgseq")
        }], false); */

        // total row 
        var v_totPkg = 0;
        var v_totWgt = 0;
        var v_totMsr = 0;
        var v_eltotPkg = 0;
        var v_eltotWgt = 0;

        // ds_ocContList 합계
        for (var i = 0; i < ds_ocContList.getRowCount(); i++) {
            v_totPkg += Number(ds_ocContList.getCellData(i, "mcpkg")) || 0;
            v_totWgt += Number(ds_ocContList.getCellData(i, "mcwgt")) || 0;
            v_totMsr += Number(ds_ocContList.getCellData(i, "mcmsr")) || 0;
        }

        // ds_ocElList 합계
        for (var i = 0; i < ds_ocElList.getRowCount(); i++) {
            v_eltotPkg += Number(ds_ocElList.getCellData(i, "pkg")) || 0;
            v_eltotWgt += Number(ds_ocElList.getCellData(i, "wgt")) || 0;
        }

        ed_totpkg.setValue(v_totPkg);
  		ed_totwgt.setValue(v_totWgt);
  		ed_totmsr.setValue(v_totMsr);
  		ed_eltotpkg.setValue(v_eltotPkg);
  		ed_eltotwgt.setValue(v_eltotWgt);

        // 빈문자열 넘어와서 replace처리
        scwin.f_removeNullString(txa_descnm);

        await scwin.f_invoiceCheck();
        await scwin.f_retrieveCarrierBkNo();
        scwin.f_Set("RETRIEVE");

        // 엑셀 파일명 설정 
        grbtn_ocContList.setDownOpts({fileName:"Container List_" + scwin.strCurDate +".xlsx",type:"4+8+16"});
        grbtn_ocElList.setDownOpts({fileName:"수출신고_" + scwin.strCurDate +".xlsx",type:"4+8+16"});


        // for=ds_houseblList event=OnLoadCompleted(rowcnt)
        if (ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "pathCd") != "") {
            ds_condition_path.setCellData(0, "hhactcust", ed_hhactcust.getValue());
            ds_condition_path.setCellData(0, "path", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "pathCd"));
            ds_condition_path.setCellData(0, "hhblno", "");
            $c.sbm.execute(sbm_retrieve_path);
        }

        // gr_ocElList 컬럼 readonly 설정
        for (var i = 0; i < ds_ocElList.getTotalRow(); i++) {
            // 분할 컬럼 값이 N이면 readonly true
            if (ds_ocElList.getCellData(i, "pgb") == "N") {
                gr_ocElList.setCellReadOnly(i, "pseq", true);
            } else if (ds_ocElList.getCellData(i, "pgb") == "Y") {
                gr_ocElList.setCellReadOnly(i, "pseq", false);
            }

            // 포장기호 값이 없으면 package, Unit 수정불가능
            var mgb = ds_ocElList.getCellData(i, "mgb");
            if (mgb == "") {
                gr_ocElList.setCellReadOnly(i, "mpkg", true);
                gr_ocElList.setCellReadOnly(i, "mut", true);
            } else {
                gr_ocElList.setCellReadOnly(i, "mpkg", false);
                gr_ocElList.setCellReadOnly(i, "mut", false);
