// 그리드 팝업 처리 
scwin.f_PopUpGrid = function(disGubun, row, pWinCloseTF, pAllSearchTF) {
    // 선언부
    var rtnList;
    var pCode = "";
    var pName = "";

    switch (disGubun) {
        case "mctype":
            pCode = ds_ocContList.getCellData(row, "mctype");
            ds_ocContList.setCellData(row, "mctype","");

            udc_mctype.ilCommonPopUp(async function(rtnList) {
                                        if (rtnList != null && rtnList[0] != "N/A") {
                                            ds_ocContList.setCellData(row, "mctype", rtnList[0] || "");
                                        }
                                        await scwin.gr_ocContList_OnExit2(row, "mctype", "");
                                    }
                                    ,pCode	 //코드
                                    ,'' 	 //코드명
                                    ,pWinCloseTF		// 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,'2'				// 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
                                    ,"Code, Name"		// Title순서
                                    ,'80,230'			// 보여주는	각 컬럼들의	폭
                                    ,"3,4,5,6,7,8,9,10"	// 컬럼중에서 숨기는	컬럼 지정
                                    ,null				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null				// POP-UP뛰을때	원도우의	사용자 정의	폭
                                    ,null				// POP-UP뛰을때	우도우의	사용자 정의	높이
                                    ,null				// 윈도우 위치 Y좌표
                                    ,null				// 윈도우 위치 X좌표
                                    ,null				// 중복체크여부	("F")
                                    ,pAllSearchTF		// 전체검색허용여부	("F")
                                    ,"Type,Code,Name"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    ,'F'				// Data	건수가 0 일때 Window를 뛰우지 않음 리턴	: "N/A"
                                    );
            break;

        case "mcpkgcd":
            pCode = ds_ocContList.getCellData(row, "mcpkgcd");
            ds_ocContList.setCellData(row, "mcpkgcd","");

            udc_mcpkgcd.ilCommonPopUp(function(rtnList) {
