                                    ,pWinCloseTF		// 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,'2'				// 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
                                    ,"Code, Name"		// Title순서
