// 그리드 팝업
scwin.gr_ocContList_ontextimageclick = function (rowIndex, columnIndex) {
    var row = rowIndex;
    var col = gr_ocContList.getFocusedColumnID();

    switch(col){
        case "mctype":
            scwin.f_PopUpGrid("mctype", row, "F");
            break;
        case "mcpkgcd":
            scwin.f_PopUpGrid("mcpkgcd", row, "F");
            break;
    }
};

scwin.gr_ocElList_ontextimageclick = function (rowIndex, columnIndex) {
    var row = rowIndex;
    var col = gr_ocElList.getFocusedColumnID();

    switch(col){
        case "unit":
            scwin.f_PopUpGrid("unit", row, "F");
            break;
        case "mut":
            scwin.f_PopUpGrid("mut", row, "F");
            break;
    }
};

// gr_ocContList event=OnExit(row,colId,olddata) : 이벤트3개, 
scwin.gr_ocContList_onafteredit = async function (row, columnIndex, value) {
    var colId = gr_ocContList.getFocusedColumnID();

    switch (colId) {
        case "mccntno": // 3269
            for (var i = 0; i < ds_ocContList.getRowCount() - 1; i++) {
                for (var j = i + 1; j <= ds_ocContList.getRowCount(); j++) {

                    var v1 = ds_ocContList.getCellData(i, "mccntno");
                    var v2 = ds_ocContList.getCellData(j, "mccntno");

                    // AUTO 생성 시(둘 다 빈값이면 skip)
                    if ($c.util.isEmpty(v1) && $c.util.isEmpty(v2)) {
                        continue;
                    }

                    if (v1 == v2) {
                        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, ["Container"]); // @은(는) 중복될 수 없습니다.

                        // 그리드 포커스 + 컬럼 포커스
                        gr_ocContList.focus();
                        gr_ocContList.setFocusedCell(j, "mccntno", true);
                        return;
                    }
                }
            }

            break;

        case "mctype":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (value != "") {
                ds_ocContList.setCellData(row, colId, value);
                scwin.f_PopUpGrid("mctype", row, "T");
            //Name field 존재시 check.
            //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else { // if(ds_ocContList.NameValue(Row,Colid).trim() == "") {
                ds_ocContList.setCellData(row, "mctype", "");
            }
            break;

        case "mcpkgcd":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (value != ""){
                ds_ocContList.setCellData(row, colId, value);
                scwin.f_PopUpGrid("mcpkgcd", row, "T");
            //Name field 존재시 check.
