// <!-- DATASET EVENT : Container ds_ocContList에서 onRowPosChanged이벤트 발생시  -->
scwin.ds_ocContList_onrowpositionchange = function (info) {     // info: oldRowIndex, newRowIndex
    //행추가인 경우만 입력 가능
    var rowIndex = info.newRowIndex;
	if (ds_ocContList.getRowStatus(rowIndex) == "C") {
        gr_ocContList.setCellReadOnly(rowIndex, "mccntno", false);
	} else {
        gr_ocContList.setCellReadOnly(rowIndex, "mccntno", true);
	}
};

// <!-- DATASET EVENT : El ds_ocElList에서 onRowPosChanged이벤트 발생시  -->
scwin.ds_ocElList_onrowpositionchange = function (info) {
    //행추가인 경우만 입력 가능
    var rowIndex = info.newRowIndex;
	if (ds_ocElList.getRowStatus(rowIndex) == "C") {
        gr_ocElList.setCellReadOnly(rowIndex, "elno", false);
	} else {
        gr_ocElList.setCellReadOnly(rowIndex, "elno", true);
	}
};

scwin.ds_ocElList_oncelldatachange = function (info) {
    var rowIndex = info.rowIndex;
    var colId = info.colID;

    // 분할
    if (colId == "pgb") {
        if (ds_ocElList.getCellData(rowIndex, "pgb") == "N") {
            gr_ocElList.setCellReadOnly(rowIndex, "pseq", true);
        } else if (ds_ocElList.getCellData(rowIndex, "pgb") == "Y") {
            gr_ocElList.setCellReadOnly(rowIndex, "pseq", false);
        }
    }

    // 포장기호
    if (colId == "mgb") {
        if (ds_ocElList.getCellData(rowIndex, "mgb") == "") {
            gr_ocElList.setCellReadOnly(rowIndex, "mpkg", true);
            gr_ocElList.setCellReadOnly(rowIndex, "mut", true);
        } else {
            gr_ocElList.setCellReadOnly(rowIndex, "mpkg", false);
            gr_ocElList.setCellReadOnly(rowIndex, "mut", false);
        }
    }
};


