// for=gr_ocContList event=OnExit(Row,Colid,olddata)
scwin.gr_ocElList_onafteredit = async function (Row, columnIndex, value) {
    var Colid = gr_ocElList.getFocusedColumnID();

    // 수출신고번호 입력 시, '-' 기호 뺀 상태로 변경
	if (Colid == "elno") {
		ds_ocElList.setCellData(Row, "elno", ds_ocElList.getCellData(Row, "elno").replace(/[-\s]/g, ''));
	}

	// 수출신고번호 중복 check   OnExit event
	for (i = 0; i < ds_ocElList.getTotalRow(); i++) {
        for (j = i + 1; j < ds_ocElList.getTotalRow(); j++) {
            if (ds_ocElList.getCellData(i,"elno") == ds_ocElList.getCellData(j,"elno")) {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, ["elno"]);  //@은(는) 중복될 수 없습니다.
                gr_ocElList.focus();
                gr_ocElList.setFocusedCell(i, "elno");      //gr_ocElList.setColumn("elno");
                return;
            }
        }
 	}

    switch (Colid) {
        case "unit":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (value != ""){
                ds_ocElList.setCellData(Row, Colid, value);
                scwin.f_PopUpGrid("unit", Row, "T");
            //Name field 존재시 check.
            //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else if(value == "") {
                ds_ocElList.setCellData(Row,"unit", "");
            }
            break;

        case "mut":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (value != ""){
                ds_ocElList.setCellData(Row, Colid, value);
                scwin.f_PopUpGrid("mut", Row, "T");
            //Name field 존재시 check.
            //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else if(value == "") {
                ds_ocElList.setCellData(Row,"mut", "");
            }
            break;

        case "elno":
            v_elno = "";
            ds_ocElList.setCellData(Row, Colid, value);
            v_elno = ds_ocElList.getCellData(Row,"elno");
            if(rd_hhmnfgb.getValue() == "E") { //Shipment Type Export
                //f_elnoExportCheck(v_elno);
            } else if ((rd_hhmnfgb.getValue() == "I")) { // Shipment Type Reshipment
                //f_elnoReshipmentCheck(v_elno);
            }
            break;

        default:
            break;
    }
};



scwin.cf_NumChangeEng = function(num) {
    num = parseInt(num, 10);
    if (isNaN(num)) return "";

    const ones = ["", "ONE", "TWO", "THREE", "FOUR", "FIVE", "SIX", "SEVEN", "EIGHT", "NINE"];
    const teens = ["TEN", "ELEVEN", "TWELVE", "THIRTEEN", "FOURTEEN", "FIFTEEN", "SIXTEEN", "SEVENTEEN", "EIGHTEEN", "NINETEEN"];
    const tens = ["", "", "TWENTY", "THIRTY", "FORTY", "FIFTY", "SIXTY", "SEVENTY", "EIGHTY", "NINETY"];

    function convert(n) {
        let result = "";

        if (n >= 1000) {
            result += ones[Math.floor(n / 1000)] + " THOUSAND ";
            n %= 1000;
        }
        if (n >= 100) {
            result += ones[Math.floor(n / 100)] + " HUNDRED ";
            n %= 100;
        }
        if (n >= 20) {
            result += tens[Math.floor(n / 10)] + " ";
            n %= 10;
        } else if (n >= 10) {
            result += teens[n - 10] + " ";
            return result.trim();
        }
        if (n > 0) {
            result += ones[n] + " ";
        }

        return result.trim();
    }

    return convert(num);
}


